import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int maxLength = 10; // Maximum length of buffer

        // Check if user input exceeds maximum length
        if (userInput.length() > maxLength) {
            System.out.println("Input exceeds maximum length of " + maxLength + ". Please enter a shorter string.");
            return;
        }

        char[] buffer = new char[maxLength];

        // Copy user input into the buffer with proper length checking
        userInput.getChars(0, Math.min(userInput.length(), maxLength), buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
